import subprocess

def list_files(path):
    try:
        result = subprocess.run(['ls', path], capture_output=True, text=True, check=True)
        files = result.stdout.strip().split('\n')
        return [f for f in files if f] if files != [''] else []
    except subprocess.CalledProcessError:
        return []

